// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedDay, setSelectedDay] = useState<string>('');

  const normalizeConditionToIcon = useCallback((condition: string): string => {
    const lower = condition.toLowerCase();
    if (lower.includes('sun') || lower.includes('clear')) return '☀️';
    if (lower.includes('cloud')) return '☁️';
    if (lower.includes('rain') || lower.includes('drizzle') || lower.includes('shower')) return '🌧️';
    if (lower.includes('storm') || lower.includes('thunder')) return '⛈️';
    if (lower.includes('snow') || lower.includes('blizzard') || lower.includes('sleet')) return '❄️';
    if (lower.includes('wind')) return '💨';
    if (lower.includes('fog') || lower.includes('mist') || lower.includes('haze')) return '🌫️';
    return '🌤️';
  }, []);

  const displayUnit = useMemo(() => {
    const normalized = (props.unit ?? '').trim();
    return normalized || 'C';
  }, [props.unit]);

  const safeForecast = useMemo(() => {
    return Array.isArray(props.forecast) ? props.forecast.slice(0, 5) : [];
  }, [props.forecast]);

  useEffect(() => {
    if (safeForecast.length > 0 && !selectedDay) {
      setSelectedDay(safeForecast[0].day ?? '');
    }
    if (safeForecast.length === 0 && selectedDay) {
      setSelectedDay('');
    }
  }, [safeForecast, selectedDay]);

  const currentConditionIcon = useMemo(() => normalizeConditionToIcon(props.condition), [props.condition, normalizeConditionToIcon]);

  const selectedForecast = useMemo(() => {
    if (safeForecast.length === 0) return null;
    const match = safeForecast.find((item) => (item.day ?? '') === selectedDay);
    return match ?? safeForecast[0];
  }, [safeForecast, selectedDay]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        radius="xl"
        shadow="md"
      >
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="start">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                {props.city}
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Current conditions
              </Text>
            </Stack>
            <Badge variant="default">
              {displayUnit}
            </Badge>
          </Row>

          <Row justify="between" align="center" wrap>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Text
                is="span"
                size="4xl"
                weight="bold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {props.temperature}°{displayUnit}
              </Text>
            </Row>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Icon name={currentConditionIcon} size={28} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="bodyLarge" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {props.condition}
              </Text>
            </Row>
          </Row>

          <Row gap="var(--ggui-spacing-4)" wrap>
            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
            >
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Stack>
            </Box>

            <Box
              padding="var(--ggui-spacing-4)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-md, 8px)"
            >
              <Stack gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed}
                </Text>
              </Stack>
            </Box>

            {selectedForecast && (
              <Box
                padding="var(--ggui-spacing-4)"
                background="var(--ggui-color-container, #ede9fe)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
              >
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onContainer, #4c1d95)">
                    Selected Day
                  </Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onContainer, #4c1d95)">
                    {(selectedForecast.day ?? 'N/A')} • H {(selectedForecast.high ?? 0)}°{displayUnit} / L {(selectedForecast.low ?? 0)}°{displayUnit}
                  </Text>
                </Stack>
              </Box>
            )}
          </Row>

          <Divider margin="var(--ggui-spacing-2)" />

          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              5-Day Forecast
            </Text>
            {safeForecast.length === 0 ? (
              <Alert variant="info" title="No forecast data">
                Forecast is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap>
                {safeForecast.map((item, index) => {
                  const dayLabel = item.day ?? `Day ${index + 1}`;
                  const iconValue = item.icon ?? normalizeConditionToIcon(props.condition);
                  const isActive = dayLabel === selectedDay || (!selectedDay && index === 0);

                  return (
                    <Card
                      key={`${dayLabel}-${index}`}
                      as={Clickable}
                      onClick={() => setSelectedDay(dayLabel)}
                      padding="var(--ggui-spacing-2)"
                      radius="md"
                      shadow="sm"
                      border
                      hoverStyle={{ opacity: 0.92 }}
                    >
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text
                          variant="caption"
                          weight={isActive ? 'bold' : 'medium'}
                          color={isActive ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        >
                          {dayLabel}
                        </Text>
                        <Icon
                          name={iconValue}
                          size={22}
                          color={isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        />
                        <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                          {(item.high ?? 0)}°{displayUnit} / {(item.low ?? 0)}°{displayUnit}
                        </Text>
                      </Stack>
                    </Card>
                  );
                })}
              </Row>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

