import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [touchedName, setTouchedName] = useState<boolean>(false);
  const [touchedEmail, setTouchedEmail] = useState<boolean>(false);
  const [hasSubmitted, setHasSubmitted] = useState<boolean>(false);

  const totalSteps = 5;
  const isSatisfactionConfigValid = props.satisfactionLabels.length > 0;
  const isFeatureConfigValid = props.featureOptions.length > 0;

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = useMemo(() => {
    if (!touchedName) return '';
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name, touchedName]);
  const emailError = useMemo(() => {
    if (!touchedEmail) return '';
    if (!email.trim()) return 'Email is required.';
    if (!isEmailValid) return 'Please enter a valid email address.';
    return '';
  }, [email, touchedEmail, isEmailValid]);

  const satisfactionOptions = useMemo(() => {
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label,
    }));
  }, [props.satisfactionLabels]);

  const isSatisfactionValid = useMemo(() => {
    return satisfaction >= 1 && satisfaction <= props.satisfactionLabels.length;
  }, [satisfaction, props.satisfactionLabels.length]);

  const stepValid = useMemo(() => {
    if (step === 1) return Boolean(name.trim()) && Boolean(email.trim()) && isEmailValid;
    if (step === 2) return isSatisfactionConfigValid && isSatisfactionValid;
    if (step === 3) return isFeatureConfigValid;
    if (step === 4) return comments.length <= 500;
    if (step === 5) return isSatisfactionConfigValid && isFeatureConfigValid && isSatisfactionValid;
    return true;
  }, [step, name, email, isEmailValid, isSatisfactionConfigValid, isSatisfactionValid, isFeatureConfigValid, comments]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (!stepValid) return;
    setStep((prev) => (prev < totalSteps ? prev + 1 : prev));
  }, [stepValid, totalSteps]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    if (step !== 5 || !stepValid || hasSubmitted) return;
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      features,
      comments: comments.trim(),
    };
    if ((props as Props & { onSubmit?: (payload: ActionSubmitPayload) => void }).onSubmit) {
      (props as Props & { onSubmit?: (payload: ActionSubmitPayload) => void }).onSubmit?.(payload);
    }
    setHasSubmitted(true);
  }, [step, stepValid, hasSubmitted, name, email, satisfaction, features, comments, props]);
  useEffect(() => {
    if (step === 1) {
      if (touchedName && name.trim()) setTouchedName(true);
      if (touchedEmail && email.trim()) setTouchedEmail(true);
    }
  }, [step, name, email, touchedName, touchedEmail]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="default">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={step} max={totalSteps} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Your Details</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  setName(value);
                  if (!touchedName) setTouchedName(true);
                }}
                required
                error={nameError}
                placeholder="Enter your name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  setEmail(value);
                  if (!touchedEmail) setTouchedEmail(true);
                }}
                required
                error={emailError}
                placeholder="Enter your email"
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              {!isSatisfactionConfigValid ? (
                <Alert variant="error" title="Missing rating options">
                  Satisfaction labels are required to continue.
                </Alert>
              ) : (
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction ? String(satisfaction) : ''}
                  onChange={(value) => setSatisfaction(Number(value))}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              )}
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Select all that apply.</Text>
              {!isFeatureConfigValid ? (
                <Alert variant="error" title="Missing feature options">
                  Feature options are required to continue.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))}
                </Stack>
              )}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={(value) => setComments(value.slice(0, 500))}
                maxLength={500}
                showCount
                placeholder="Share anything else..."
                helperText="Maximum 500 characters"
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Responses</Heading>
              {(!isSatisfactionConfigValid || !isFeatureConfigValid) && (
                <Alert variant="error" title="Cannot submit">
                  Required survey options are missing. Please go back and check configuration.
                </Alert>
              )}
              <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><Text is="span" weight="semibold">Name:</Text> {name.trim()}</Text>
                  <Text><Text is="span" weight="semibold">Email:</Text> {email.trim()}</Text>
                  <Text>
                    <Text is="span" weight="semibold">Satisfaction:</Text>{' '}
                    {isSatisfactionValid ? props.satisfactionLabels[satisfaction - 1] : 'Not selected'}
                  </Text>
                  <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                  <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments'}</Text>
                </Stack>
              </Card>
            </Stack>
          )}


        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onPress={goBack} disabled={step === 1}>
            Back
          </Button>
          {step < totalSteps ? (
            <Button
              variant="primary"
              onPress={() => {
                if (step === 1) {
                  setTouchedName(true);
                  setTouchedEmail(true);
                }
                goNext();
              }}
              disabled={!stepValid}
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onPress={handleSubmit} disabled={!stepValid || hasSubmitted}>
              {hasSubmitted ? 'Submitted' : 'Submit'}
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

