import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: 'move' | 'edit' | 'create'; taskId: string; data: { id?: string; column?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }>>([]);
  const [addingColumnId, setAddingColumnId] = useState<string>('');
  const [newTaskTitle, setNewTaskTitle] = useState<string>('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    const columnIds = (props.columns || []).map((column, index) => column.id || `column-${index}`);
    const normalized = (props.tasks || []).map((task, index) => {
      const fallbackColumn = columnIds[0] || '';
      const candidateColumn = task.column || fallbackColumn;
      return {
        id: task.id || `task-${index}`,
        title: task.title || 'Untitled task',
        priority: task.priority || 'medium',
        assignee: task.assignee || 'NA',
        column: columnIds.includes(candidateColumn) ? candidateColumn : fallbackColumn,
        dueDate: task.dueDate || '',
      };
    });
    setBoardTasks(normalized);
  }, [props.tasks, props.columns]);

const processedEventKeysRef = useRef<Record<string, boolean>>({});

  useEffect(() => {
    const events = taskChanged.all || [];
    const columnIds = (props.columns || []).map((column, index) => column.id || `column-${index}`);
    const fallbackColumn = columnIds[0] || '';

    events.forEach((event, index) => {
      if (!event || !event.task || !event.task.id) {
        return;
      }
      const incoming = event.task;
      const incomingId = incoming.id;
      const eventKey = `${event.action || 'edit'}:${incomingId}:${incoming.title || ''}:${incoming.priority || ''}:${incoming.assignee || ''}:${incoming.column || ''}:${incoming.dueDate || ''}:${index}`;
      if (processedEventKeysRef.current[eventKey]) {
        return;
      }
      processedEventKeysRef.current[eventKey] = true;

      if (event.action === 'delete') {
        setBoardTasks((prev) => prev.filter((task) => task.id !== incomingId));
        return;
      }
      setBoardTasks((prev) => {
        const existingIndex = prev.findIndex((task) => task.id === incomingId);
        const existingTask = existingIndex >= 0 ? prev[existingIndex] : null;
        const candidateColumn = incoming.column || existingTask?.column || fallbackColumn;
        const normalizedTask = {
          id: incomingId,
          title: incoming.title || existingTask?.title || 'Untitled task',
          priority: incoming.priority || existingTask?.priority || 'medium',
          assignee: incoming.assignee || existingTask?.assignee || 'NA',
          column: columnIds.includes(candidateColumn) ? candidateColumn : (existingTask?.column || fallbackColumn),
          dueDate: incoming.dueDate || existingTask?.dueDate || '',
        };
        if (existingIndex === -1) {
          return [...prev, normalizedTask];
        }
        const next = [...prev];
        if (editingTaskId === incomingId) {
          return next;
        }
        next[existingIndex] = { ...next[existingIndex], ...normalizedTask };
        return next;
      });
    });
  }, [taskChanged.all, props.columns, editingTaskId]);

  const columns = useMemo(() => {
    return (props.columns || []).map((column, index) => ({
      id: column.id || `column-${index}`,
      name: column.name || `Column ${index + 1}`
    }));
  }, [props.columns]);

  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate: string }>> = {};
    columns.forEach((column) => {
      grouped[column.id] = [];
    });
    boardTasks.forEach((task) => {
      if (!grouped[task.column]) {
        grouped[task.column] = [];
      }
      grouped[task.column].push(task);
    });
    return grouped;
  }, [boardTasks, columns]);

  const completedCount = useMemo(() => {
    const doneColumn = columns.find((column) => column.name.toLowerCase() === 'done' || column.id.toLowerCase() === 'done');
    if (!doneColumn) {
      return 0;
    }
    return (tasksByColumn[doneColumn.id] || []).length;
  }, [columns, tasksByColumn]);

  const totalCount = boardTasks.length;

  const getBadgeVariant = useCallback((priority: 'low' | 'medium' | 'high'): 'default' | 'warning' | 'error' => {
    if (priority === 'high') {
      return 'error';
    }
    if (priority === 'medium') {
      return 'warning';
    }
    return 'default';
  }, []);

  const moveTask = useCallback((taskId: string, nextColumn: string) => {
    if (!nextColumn) {
      return;
    }
    const currentTask = boardTasks.find((task) => task.id === taskId);
    if (!currentTask || currentTask.column === nextColumn) {
      return;
    }
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: nextColumn } : task)));
    taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
  }, [taskUpdate, boardTasks]);

  const startEdit = useCallback((taskId: string, currentTitle: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(currentTitle);
  }, []);

  const saveEdit = useCallback((taskId: string) => {
    const nextTitle = editingTitle.trim();
    const existingTask = boardTasks.find((task) => task.id === taskId);
    if (!existingTask) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    if (!nextTitle) {
      setEditingTaskId('');
      setEditingTitle('');
      return;
    }
    if (existingTask.title !== nextTitle) {
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: nextTitle } : task)));
      taskUpdate({ action: 'edit', taskId, data: { title: nextTitle } });
    }
    setEditingTaskId('');
    setEditingTitle('');
  }, [editingTitle, boardTasks, taskUpdate]);

  const createTask = useCallback(() => {
    const title = newTaskTitle.trim();
    if (!title) {
      return;
    }
    const todoColumn = columns[0]?.id || '';
    if (!todoColumn) {
      return;
    }
    const newId = `task-${Date.now()}`;
    const created = {
      id: newId,
      title,
      priority: newTaskPriority,
      assignee: 'NA',
      column: todoColumn,
      dueDate: '',
    } as const;
    setBoardTasks((prev) => [...prev, created]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingColumnId('');
    taskUpdate({ action: 'create', taskId: newId, data: { id: newId, column: todoColumn, title, priority: newTaskPriority, assignee: 'NA', dueDate: '' } });
  }, [newTaskTitle, newTaskPriority, taskUpdate, columns]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
          <Row gap="var(--ggui-spacing-4)" justify="between" align="center" wrap>
            <Heading level={3}>Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-4)">
              <Badge variant="default">Total: {totalCount}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {boardTasks.length === 0 ? (
          <Alert variant="info" title="No tasks yet">No tasks available. Add a task to get started.</Alert>
        ) : null}

        <Row gap="var(--ggui-spacing-4)" wrap align="start">
          {columns.map((column) => (
            <Card
              key={column.id}
              padding="var(--ggui-spacing-4)"
              shadow="sm"
              radius="lg"
              border
            >
              <Stack gap="var(--ggui-spacing-4)">
                <Row justify="between" align="center">
                  <Heading level={5}>{column.name}</Heading>
                  <Badge variant="default">{(tasksByColumn[column.id] || []).length}</Badge>
                </Row>

                <Stack gap="var(--ggui-spacing-3)">
                  {(tasksByColumn[column.id] || []).map((task) => (
                    <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" radius="md" border>
                      <Stack gap="var(--ggui-spacing-2)">
                        {editingTaskId === task.id ? (
                          <Row gap="var(--ggui-spacing-2)" align="end">
                            <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} />
                            <Button onPress={() => saveEdit(task.id)} size="sm">Save</Button>
                          </Row>
                        ) : (
                          <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                            <Text
                              as={Clickable}
                              onDoubleClick={() => startEdit(task.id, task.title)}
                              color="var(--ggui-color-onSurface, #18181b)"
                              truncate
                            >
                              {task.title}
                            </Text>
                            <Button size="xs" variant="ghost" onPress={() => startEdit(task.id, task.title)}>Edit</Button>
                          </Row>
                        )}

                        <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                          {editingTaskId === task.id ? (
                            <Select
                              label="Edit priority"
                              value={task.priority}
                              onChange={(value) => {
                                const nextPriority = (value as 'low' | 'medium' | 'high') || 'medium';
                                if (nextPriority === task.priority) {
                                  return;
                                }
                                setBoardTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, priority: nextPriority } : t)));
                                taskUpdate({ action: 'edit', taskId: task.id, data: { priority: nextPriority } });
                              }}
                              options={[
                                { value: 'low', label: 'Low' },
                                { value: 'medium', label: 'Medium' },
                                { value: 'high', label: 'High' },
                              ]}
                            />
                          ) : (
                            <Badge variant={getBadgeVariant(task.priority)}>{task.priority}</Badge>
                          )}
                          <Avatar name={task.assignee} size="xs" />
                          {task.dueDate ? <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Due: {task.dueDate}</Text> : null}
                        </Row>

                        <Select
                          label="Move task"
                          value={task.column}
                          onChange={(value) => moveTask(task.id, value)}
                          options={columns.map((c) => ({ value: c.id, label: c.id === task.column ? `${c.name} (Current)` : `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {columns[0] && column.id === columns[0].id && addingColumnId === column.id ? (
                  <Card padding="var(--ggui-spacing-3)" shadow="none" radius="md" border>
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input label="Task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="Enter task title" />
                      <Select
                        label="Priority"
                        value={newTaskPriority}
                        onChange={(value) => setNewTaskPriority((value as 'low' | 'medium' | 'high') || 'medium')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                      />
                      <Row gap="var(--ggui-spacing-2)">
                        <Button size="sm" onPress={() => createTask()}>Create</Button>
                        <Button size="sm" variant="ghost" onPress={() => setAddingColumnId('')}>Cancel</Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : null}

                {columns[0] && column.id === columns[0].id ? (
                  <Button size="sm" variant="outline" fullWidth onPress={() => setAddingColumnId(column.id)}>
                    + Add Task
                  </Button>
                ) : null}

              </Stack>
            </Card>
          ))}
        </Row>
      </Stack>
    </Container>

  );
}

