    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draft, setDraft] = useState<string>('');
  const [typingState, setTypingState] = useState<{ sender?: string; active?: boolean } | null>(null);
  const endRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    const messageUnsubscribe = message.subscribe((incoming) => {
      setAllMessages((prev) => [...prev, incoming]);
    });

    const typingUnsubscribe = typing.subscribe((incoming) => {
      if ((incoming.sender || '') === props.currentUser) return;
      if (incoming.active) {
        setTypingState(incoming);
      } else {
        setTypingState(null);
      }
    });

    return () => {
      messageUnsubscribe();
      typingUnsubscribe();
    };
  }, [message, typing, props.currentUser]);

  useEffect(() => {
    if (endRef.current) {
      endRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [allMessages, typingState]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (allMessages || []).forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && (last.sender || '') === (msg.sender || '')) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
