          >
            <Stack
              gap="var(--ggui-spacing-2)"
            >
              <Box>
                <Stack gap="var(--ggui-spacing-2)">
                  {(groupedMessages || []).length === 0 ? (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No messages yet.
                    </Text>
                  ) : null}
                </Stack>
              </Box>
              <Box
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surface, #fafafa)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{ maxHeight: '50vh', overflowY: 'auto' }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {(groupedMessages || []).map((group, groupIndex) => {
                    const isOwn = (group.sender || '') === props.currentUser;
                    return (
                      <Stack key={`group-${groupIndex}`} gap="var(--ggui-spacing-1)">
                        <Row justify={isOwn ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {group.sender || 'Unknown'}
                          </Text>
                        </Row>
                        {(group.items || []).map((msg, msgIndex) => (
                          <Row key={`msg-${groupIndex}-${msgIndex}`} justify={isOwn ? 'end' : 'start'}>
                            <Box
                              padding="var(--ggui-spacing-2)"
                              background={
                                isOwn
                                  ? 'var(--ggui-color-primary-600, #0284c7)'
                                  : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                              }
                              borderRadius="var(--ggui-shape-radius-md, 8px)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={
                                    isOwn
                                      ? 'var(--ggui-color-surface, #fafafa)'
                                      : 'var(--ggui-color-onSurface, #18181b)'
                                  }
                                >
                                  {msg.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={
                                    isOwn
                                      ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                      : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                  }
                                >
                                  {formatTimestamp(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          </Row>
                        ))}
                      </Stack>
                    );
                  })}
                  <Box><div ref={endRef} /></Box>
                </Stack>
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type your message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" disabled={!draft.trim()} onClick={handleSend}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
