export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [displayStocks, setDisplayStocks] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string>(new Date().toLocaleTimeString());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});
  const flashTimersRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  useEffect(() => {
    setDisplayStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const ticker = setInterval(() => {
      setLastUpdated(new Date().toLocaleTimeString());
    }, 1000);
    return () => {
      clearInterval(ticker);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    setDisplayStocks((prev) => {
      const next = (prev ?? []).map((stock) => {
        if (stock.symbol !== priceUpdate.latest?.symbol) {
          return stock;
        }
        return {
          ...stock,
          price: priceUpdate.latest?.price ?? stock.price,
          change: priceUpdate.latest?.change ?? stock.change,
          changePercent: priceUpdate.latest?.changePercent ?? stock.changePercent,
        };
      });

      return next;
      return next;
    });

    setLastUpdated(new Date().toLocaleTimeString());
    const symbolKey = priceUpdate.latest.symbol;
    setFlashMap((prev) => ({ ...prev, [symbolKey]: Date.now() }));
    if (flashTimersRef.current[symbolKey]) {
      clearTimeout(flashTimersRef.current[symbolKey]);
    }
    flashTimersRef.current[symbolKey] = setTimeout(() => {
      setFlashMap((prev) => {
        const next = { ...prev };
        delete next[symbolKey];
        return next;
      });
    }, 600);
  }, [priceUpdate.latest]);

