    if (!marketStatus.latest) {
      return;
    }
    if (marketStatus.latest.timestamp) {
      const parsed = new Date(marketStatus.latest.timestamp);
      if (!Number.isNaN(parsed.getTime())) {
        setLastUpdated(parsed.toLocaleTimeString());
        return;
      }
    }
    setLastUpdated(new Date().toLocaleTimeString());
  }, [marketStatus.latest]);

  useEffect(() => {
    return () => {
      Object.values(flashTimersRef.current).forEach((timer) => clearTimeout(timer));
    };
  }, []);

  const statusText = useMemo(() => {
    if (!marketStatus.latest?.status) {
      return 'unknown';
    }
    return marketStatus.latest.status;
