              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Last Updated: {lastUpdated}
                </Text>
                <Badge
                  variant={statusText === 'open' ? 'success' : statusText === 'closed' ? 'error' : 'warning'}
                  size="sm"
                >
                  {statusText}
                </Badge>
              </Row>
            </Stack>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {priceUpdate.all.length} live update{priceUpdate.all.length === 1 ? '' : 's'}
            </Text>
          </Row>
        </Card>

        {(displayStocks ?? []).length === 0 ? (
          <Card padding="var(--ggui-spacing-8)" border shadow="sm" radius="lg">
            <Stack gap="var(--ggui-spacing-2)" align="center">
              <Icon name="info" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available.
              </Text>
            </Stack>
          </Card>
        ) : (
          <Box>
            <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
              {(displayStocks ?? []).map((stock, index) => {
                const numericChange = stock.change ?? 0;
                const isPositive = numericChange >= 0;
                const accent = isPositive
                  ? 'var(--ggui-color-success, #16a34a)'
                  : 'var(--ggui-color-error, #dc2626)';
                const isFlashing = !!(stock.symbol && flashMap[stock.symbol]);

                return (
                  <Card
                    key={stock.symbol ?? `stock-${index}`}
                    padding="var(--ggui-spacing-6)"
                    border
