  const displayedAvatarOptions = useMemo(() => {
    const base = props.avatarOptions.length >= 4 ? props.avatarOptions.slice(0, 4) : props.avatarOptions;
    if (base.length >= 4) return base;
    const fallback = ['😀', '😎', '🚀', '🎨'];
    const merged = [...base];
    let i = 0;
    while (merged.length < 4 && i < fallback.length) {
      if (!merged.includes(fallback[i])) merged.push(fallback[i]);
      i += 1;
    }
    return merged.slice(0, 4);
  }, [props.avatarOptions]);





  const goNext = useCallback(() => {
    if (!canNext) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canNext]);

  const goBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const submit = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [stepOneValid, stepTwoValid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="default">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Row gap="var(--ggui-spacing-2)">
              <Badge variant={step >= 1 ? 'success' : 'default'}>1</Badge>
              <Badge variant={step >= 2 ? 'success' : 'default'}>2</Badge>
              <Badge variant={step >= 3 ? 'success' : 'default'}>3</Badge>
            </Row>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
          radius="lg"
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : ''}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length === 0 ? 'Email is required' : emailValid ? '' : 'Enter a valid email address'}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {displayedAvatarOptions.map((option) => (
                      <Card
                        key={option}
                        as={Clickable}
                        onClick={() => setAvatar(option)}
                        padding="var(--ggui-spacing-2)"
                        border
                        radius="md"
                        shadow="none"
                        style={{
                          borderColor: avatar === option ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                          background: avatar === option ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                          minWidth: '48px',
                          textAlign: 'center',
                        }}
                      >
                        <Text size="xl" align="center">{option}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={displayedRoleOptions.map((item) => ({ value: item, label: item }))}
                  placeholder="Select your role"
                  required
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Current theme preference: {theme}
                </Text>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review &amp; Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Almost done">
                  Please confirm the details above, then complete setup.
                </Alert>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={goBack} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button variant="primary" onClick={goNext} disabled={!canNext}>
                Next
              </Button>
            )}
            {step === 3 && (
              <>
                <Button variant="secondary" onClick={() => setStep(2)}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={submit} disabled={!stepOneValid || !stepTwoValid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>

  );
}
